import React from 'react';
import { BrowserRouter, Routes, Route, Link } from 'react-router-dom';
import Home from './pages/Home';
import Relatorios from './pages/Relatorios';
import CadastroCliente from './pages/CadastroCliente';
import NovaOs from './pages/NovaOs';

function App() {
    return (
        <BrowserRouter>
            <div style={{ padding: '20px' }}>
                <nav style={{ marginBottom: '20px', display: 'flex', gap: '15px', borderBottom: '1px solid #ccc', paddingBottom: '10px', flexWrap: 'wrap' }}>
                    <Link to="/" style={{ textDecoration: 'none', color: '#007bff' }}>🏠 Home</Link>
                    <Link to="/clientes/novo" style={{ textDecoration: 'none', color: '#007bff' }}>➕ Cadastrar Cliente</Link>
                    <Link to="/os/nova" style={{ textDecoration: 'none', color: '#007bff' }}>🛠️ Nova OS</Link>
                    <Link to="/relatorios" style={{ textDecoration: 'none', color: '#007bff' }}>📊 Relatórios</Link>
                </nav>
                <Routes>
                    <Route path="/" element={<Home />} />
                    <Route path="/clientes/novo" element={<CadastroCliente />} />
                    <Route path="/os/nova" element={<NovaOs />} />
                    <Route path="/relatorios" element={<Relatorios />} />
                </Routes>
            </div>
        </BrowserRouter>
    );
}

export default App;
